import '../core/utils/date_time_utils.dart';
class PredictionModel { final String id,matchTitle,teamAName,teamBName,status; final int teamAScore,teamBScore; final String? scorerName; final int? points; final DateTime? submittedAt; PredictionModel({required this.id,required this.matchTitle,required this.teamAName,required this.teamBName,required this.teamAScore,required this.teamBScore,required this.status,this.scorerName,this.points,this.submittedAt}); factory PredictionModel.fromMap(Map<String,dynamic> m)=>PredictionModel(id:(m['id']??'').toString(),matchTitle:(m['match_title']??'Match').toString(),teamAName:(m['team_a_name']??'Team A').toString(),teamBName:(m['team_b_name']??'Team B').toString(),teamAScore:int.tryParse('${m['team_a_score']??0}')??0,teamBScore:int.tryParse('${m['team_b_score']??0}')??0,status:(m['status']??'').toString(),scorerName:m['scorer_name']?.toString(),points:int.tryParse('${m['points']??''}'),submittedAt:DateTimeUtils.parse(m['submitted_at']??m['created_at'])); }
